function Projects() {
  const projects = [
    "Student Marketplace App",
    "AI-HealthCare Chatbot",
    "AWS Hackathon Project"
  ];

  return (
    <section>
      <h2>Projects</h2>
      <ul>
        {projects.map((p, index) => (
          <li key={index}>{p}</li>
        ))}
      </ul>
    </section>
  );
}

export default Projects;
